"""
MKT Original Commentary — Judges chapters 9–10
Run: python3 scripts/zc-original-judges-9-10.py

Chapters covered:
- Ch9: Abimelech's kingship — first attempted monarchy, Jotham's bramble parable,
  Abimelech's defeat by a millstone (a woman's hand), divine curse-fulfillment
- Ch10: Tola and Jair; another apostasy cycle with the fullest list of foreign gods;
  YHWH's covenant confrontation and the remarkable divine-pathos verse (10:16)

Key philological foci:
- Ch9: melek (king) — the anti-kingship polemic; ʾeḥāḏ ʾaḇem (same father);
  māšal (parable/rule); ʾātāḏ (bramble/thorn); ʾēš min-hāʾātāḏ (fire from bramble);
  bêt millôʾ (House of Millo); pelah-rekaḇ (millstone); rûaḥ rāʿāh (evil spirit);
  qillēl/ʾālāh (curse); šillem (pay back/requite)
- Ch10: šāpat (to judge) for Tola/Jair; the sevenfold list of foreign god names (10:6);
  YHWH's covenant sarcasm (10:14); ʾōmer... lōʾ ʾôsîp (I will save no more);
  wayyiqṣar napšô (his soul was short/impatient — divine pathos);
  ʿāmal (toil/misery); gārûr (sojourning — Ammonite oppression)
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(layer, book):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    return json.loads(p.read_text()) if p.exists() else {}

def save_comm(layer, book, data):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

ORIGINAL = {
  "9": {
    "1": "<p><em>wayyēlek ʾăḇîmeleḵ ben-yərubbaʿal šəkemāh ʾel-ʾăḥê ʾimmô</em> — 'Abimelech son of Jerubbaal went to Shechem to his mother's brothers.' <em>ʾăḇîmeleḵ</em> (H40) means 'my father is king' — an ironic name for a man who will seize kingship in his father's memory, despite Gideon's explicit refusal of dynastic succession (8:23: 'I will not rule over you, nor shall my son rule over you; YHWH will rule over you'). Shechem (<em>šekem</em> H7927) is the ancient covenant city where Israel renewed covenant with YHWH at the end of Joshua (Josh 24) — its selection as the headquarters of Israel's first kingship attempt is deliberate anti-covenant geography.</p>",
    "2": "<p><em>mî-ṭôḇ lākem hāmšōl bākem šibʿîm ʾîš kōl bənê-yərubbaʿal ʾim-māšol-bākem ʾîš ʾeḥāḏ</em> — 'Which is better for you: that seventy men rule over you — all the sons of Jerubbaal — or that one man rule over you?' <em>māšal</em> (H4910, to rule/have dominion) is the key political verb: Abimelech is campaigning for a kind of rule that was itself contested. His rhetoric presents a false binary: either 70 joint rulers (chaos) or one strong man (stability). The emotional appeal — 'he is your bone and flesh' (<em>ʿaṣmêkem ûḇəśarkêkem</em>) — co-opts the covenant kinship formula (Gen 2:23; 2 Sam 5:1) for political manipulation.</p>",
    "4": "<p><em>wayyittənû-lô šibʿîm kāsep mibêt baʿal bərît wayyiškor bāhem ʾăḇîmeleḵ ʾănāšîm rêqîm ûpōḥăzîm</em> — 'They gave him seventy pieces of silver from the temple of Baal-Berith, and Abimelech hired worthless and reckless men with them.' <em>bêt baʿal bərît</em> (H1168 H1285 — House of Baal-of-the-Covenant/Baal-Berith) is the pagan covenant-shrine at Shechem — the contrast with YHWH's covenant at the same city (Josh 24) is the text's sharpest irony. <em>rêqîm</em> (H7386, empty/worthless men) and <em>pōḥăzîm</em> (H6348 root, reckless/frivolous) describe hired mercenaries with no covenant loyalties — the army you get when you fund kingship with Baal's money.</p>",
    "5": "<p><em>wayyāḇōʾ ḇêt ʾāḇîw ʿoprātāh wayyahărog ʾet-ʾeḥāyw bənê-yərubbaʿal šibʿîm ʾîš ʿal-ʾeḇen ʾaḥāt</em> — 'He went to his father's house at Ophrah and killed his brothers the sons of Jerubbaal — seventy men — on one stone.' <em>ʾeḇen ʾaḥāt</em> (one stone) — execution on a single stone suggests formal-ritual killing, possibly a sacrificial stone. The killing of seventy brothers is an extreme act of dynastic consolidation paralleled in ancient Near Eastern royal succession practices (the Assyrian annals record similar fratricide). The number seventy — the full measure of Gideon's legitimate sons — is also the number of Jacob's household (Gen 46:27) and of the elders of Israel (Exod 24:1), making the massacre of all seventy a symbolic destruction of covenant Israel's leadership.</p>",
    "7": "<p><em>wayyaggîḏû ləyôṯām wayyēlek wayyaʿămod bərōš har-gərizîm</em> — 'When they told Jotham, he went and stood on top of Mount Gerizim and cried aloud.' Mount Gerizim (<em>har gərizîm</em> H1630) is the mountain of blessing in Deuteronomy's covenant ceremony (Deut 11:29; 27:12) — the blessing mountain becomes the platform for Jotham's curse-parable. <em>wayyiṣʿaq</em> (H6817, he cried out loudly) — Jotham's parable is shouted down from the mountain, a prophetic proclamation rather than a private conversation. He is the sole surviving legitimate heir, speaking his father's theology.</p>",
    "8": "<p><em>hālôk hālkû hāʿēṣîm limšōaḥ ʿălêhem meleḵ</em> — 'The trees went out to anoint a king over themselves.' The fable (<em>māšal</em> H4912 — parable/proverb/allegory) uses the device of talking trees to satirize the Shechemites' kingship project. <em>māšaḥ</em> (H4886, to anoint) — anointing with oil was the investiture ceremony for kings, priests, and prophets; the trees' offer to the olive, fig, and vine parodies the legitimate anointing of YHWH's chosen king. Each tree's refusal to stop producing its useful fruit to 'sway over the trees' encodes the wisdom principle: truly productive persons do not abandon their calling for empty political power.</p>",
    "9": "<p><em>wayyōʾmer lāhem hāzayit heḥādaltî ʾet-dišnî ʾăšer-bî yəkaḇḏû ʾĕlōhîm wăʾănāšîm ûḇāʾtî lānûaʿ ʿal-hāʿēṣîm</em> — 'The olive tree said to them: Shall I leave my fatness (<em>dišnî</em>), by which gods and men are honored, and go to sway over the trees?' <em>dešen</em> (H1880, fatness/richness/oil) — olive oil was used in sacrifice (honoring God) and in cooking (honoring men). The olive's refusal encodes: genuine service to God and man is incompatible with the pursuit of political dominance. The fable's logic — olive, fig, vine all refuse; the bramble accepts — implies that only the useless/dangerous plant seeks to reign.</p>",
    "14": "<p><em>wayyōʾmərû kol-hāʿēṣîm ʾel-hāʾātāḏ</em> — 'Then all the trees said to the bramble.' <em>ʾātāḏ</em> (H328, bramble/buckthorn — Rhamnus palaeostinus or Ziziphus lotus) is a thorny shrub of no fruit or timber value, useful only for starting fires. Its acceptance of the kingship offer — 'Come and take shelter in my shade' — is the parable's punchline: the bramble promises shade it cannot provide (low-growing thorny shrubs give no real shade), and threatens to destroy even the cedars of Lebanon if not obeyed. <em>ʾēš tēṣēʾ min-hāʾātāḏ</em> — 'fire came out from the bramble' — dry thornbush is the most flammable vegetation, legendary as a fire-starter. The warning becomes prophecy: Abimelech the bramble will destroy those who shelter under him.</p>",
    "15": "<p><em>wayyōʾmer hāʾātāḏ ʾel-hāʿēṣîm ʾim beʾĕmet ʾattem mōšəḥîm ʾōtî ləmeleḵ ʿălêkem</em> — 'The bramble said to the trees: If in truth you are anointing me king over you...' <em>beʾĕmet</em> (H571, in truth/in faithfulness) — the bramble's challenge is a double irony: the trees cannot 'in truth' be doing this, because no genuine political community would turn to the worthless bramble. The condition is hypothetical-absurdist. <em>bōʾû ḥăsû bəṣillî</em> — 'come and take refuge in my shade' — <em>ḥāsāh</em> (H2620, to take refuge/shelter) is consistently used of taking refuge in YHWH (Ps 2:12; 5:11; 7:1). Jotham's parable implies: seeking safety in a bramble-king rather than in YHWH is the fundamental folly of Shechem's choice.</p>",
    "23": "<p><em>wayyišlaḥ ʾĕlōhîm rûaḥ rāʿāh bên ʾăḇîmeleḵ ûḇên baʿălê šəkem</em> — 'God sent an evil spirit between Abimelech and the leaders of Shechem.' <em>rûaḥ rāʿāh</em> (H7307 H7451, evil/bad spirit) — the sending of a disruptive spirit as divine judicial instrument appears also in 1 Sam 16:14 (evil spirit from YHWH troubles Saul) and 1 Kgs 22:22 (a lying spirit dispatched to deceive Ahab). The theological claim is that YHWH uses fractured relationships and betrayal as instruments of judgment. <em>bāgad</em> (H898, to act treacherously/deal deceitfully) — Shechem's treachery against Abimelech is the mechanism of YHWH's vengeance for the murder of the seventy.</p>",
    "24": "<p><em>lāḇôʾ ḥămas šibʿîm bənê-yərubbaʿal wədāmām lāśûm ʿal-ʾăḇîmeleḵ ʾăḥîhem ʾăšer hārag ʾôtām</em> — 'in order that the violence (<em>ḥāmās</em>) done to the seventy sons of Jerubbaal might come, and their blood be laid on Abimelech their brother.' <em>ḥāmās</em> (H2555, violence/wrong/injustice) is the gravest term for social/physical wrong in Hebrew — it appears in Gen 6:11 as the reason for the Flood. Blood guilt (<em>dāmîm</em> H1818) — the unpunished blood of the murdered brothers is a moral charge that must be resolved. The text tracks this resolution explicitly through the fable's fulfillment: fire from the bramble consumed the men of Shechem (v49), and the bramble was destroyed (v53-54).</p>",
    "53": "<p><em>wattiššəlēk ʾiššāh ʾaḥat pelah-rekaḇ ʿal-rōʾš ʾăḇîmeleḵ wattāroṣ ʾet-gulgultô</em> — 'A certain woman threw an upper millstone on Abimelech's head and cracked his skull.' <em>pelah-rekaḵ</em> (H6400 H7393, upper millstone) — the upper millstone (the grinding stone that rides on the fixed lower stone) was a household object associated entirely with women's grain-grinding work. Its use as a weapon is as unexpected as Jael's tent peg. <em>gulgōlet</em> (H1538, skull) — the skull-cracking detail matches the Jael event (4:21) and forms a doublet: in Judges, great military leaders are killed by women using domestic implements, because YHWH consistently reverses human expectations of who the decisive agent will be.</p>",
    "54": "<p><em>wayyimhēr wayyiqrāʾ ʾet-hannaʿar nōśēʾ kēlāyw wayyōʾmer lô šlop ḥarbekā ûḏāqərēnî-ḇāh pen-yōʾmərû lî ʾiššāh hărāgātəhû</em> — 'He quickly called to the young man who carried his armor and said: Draw your sword and kill me, so that they will not say of me: a woman killed him.' Abimelech's final concern is his reputation — he does not want the historical record to say a woman killed him. The irony is absolute: by making this request explicit he ensures the story records exactly what he feared. Hebrews 11 includes Barak but not Abimelech; the anti-king's death at a woman's hand is the text's final verdict on a life built on false power.</p>",
    "57": "<p><em>wəʾēt kol-rāʿat ʾanšê šekem hēšîḇ ʾĕlōhîm bərōʾšām wayyāḇōʾ ʾălêhem qillalat yôṯām ben-yərubbaʿal</em> — 'God also made all the evil of the men of Shechem return on their heads, and on them came the curse of Jotham son of Jerubbaal.' <em>šûḇ</em> (H7725, to return/bring back) — divine justice operates as return: what was done comes back. <em>qəlālāh</em> (H7045, curse — from <em>qālal</em> H7043, to be light/curse) is the formal covenant curse that Jotham pronounced from Gerizim (the blessing-mountain turned into a curse-platform). The narrative closes with explicit divine attribution — not fate or history but YHWH-through-Elohim who executes the curse's fulfillment.</p>"
  },
  "10": {
    "1": "<p><em>wayyāqom ʾaḥărê ʾăḇîmeleḵ ləhôšîaʿ ʾet-yiśrāʾēl tôlāʿ ben-pûʾāh ben-dôḏô ʾîš yiśśāśkār</em> — 'After Abimelech, Tola the son of Puah, son of Dodo, a man of Issachar, rose to save Israel.' <em>ləhôšîaʿ</em> (H3467, to save/deliver) — the judge's essential function stated succinctly; <em>qûm</em> (H6965, to arise/rise up) is the standard verb for YHWH raising up a deliverer. Tola's genealogy (son of Puah, son of Dodo) goes three generations — unusual depth for a minor judge, suggesting scribal memory of an actual historical figure. His name means 'worm' or 'crimson/scarlet' (<em>tôlāʿ</em> H8438 — the same word for the crimson dye from the cochineal insect, used in the tabernacle textiles, Exod 25:4).</p>",
    "3": "<p><em>wayyāqom ʾaḥărāyw yāʾîr haggileʿādî wayyišpōṭ ʾet-yiśrāʾēl ʿeśrîm ûšəṭayim šānāh</em> — 'After him arose Jair the Gileadite, who judged Israel twenty-two years.' <em>šāpaṭ</em> (H8199, to judge) — the minor judges are described by this verb without accompanying military narrative. <em>gilʿādî</em> (Gileadite — from Gilead, H1568, the Transjordan tribal territory) — Jair's origin in the Transjordan is consistent with the geographic breadth of Israel's settlement. His thirty sons riding on thirty donkeys (v4) — <em>ʿayārîm</em> H5895, young donkeys — is a status marker: donkey-riding was aristocratic in pre-horse Israel (cf. Judg 5:10 — those who ride on white donkeys). The thirty cities named 'Havvoth-jair' (H2334) are his legacy, preserving his name in the landscape.</p>",
    "6": "<p><em>wayyōsîpû bənê yiśrāʾēl laʿăśôt hāraʿ bəʿênê YHWH wayyaʿabdû ʾet-habbəʿālîm wəʾet-hāʿaštārôt wəʾet ʾĕlōhê ʾărām wəʾet ʾĕlōhê ṣîḏôn wəʾet ʾĕlōhê môʾāḇ wəʾet ʾĕlōhê bənê ʿammôn wəʾet ʾĕlōhê pəlištîm</em> — the longest and most explicit list of foreign deities in Judges. Seven specific national pantheons are named: <em>bəʿālîm</em> (Baals — plural form of Baal H1168, the storm/fertility deity), <em>ʿaštārôt</em> (Ashtaroth — H6252, plural of Ashtoreth/Astarte, the goddess of love and war), <em>ʾĕlōhê ʾărām</em> (gods of Aram — Syrian pantheon including Hadad), <em>ʾĕlōhê ṣîḏôn</em> (gods of Sidon — Phoenician deities including Baal and Asherah), <em>ʾĕlōhê môʾāḇ</em> (gods of Moab — primarily Chemosh H3645), <em>ʾĕlōhê ʿammôn</em> (gods of Ammon — primarily Molech/Milcom H4445), <em>ʾĕlōhê pəlištîm</em> (gods of the Philistines — primarily Dagon H1712). The exhaustive list emphasizes the comprehensiveness of Israel's apostasy: every surrounding people's deity has been embraced.</p>",
    "7": "<p><em>wayyiḥar-ʾap YHWH bəyiśrāʾēl wayyimkərēm bəyaḏ-pəlištîm ûbəyaḏ bənê ʿammôn</em> — 'The anger of YHWH burned against Israel, and he sold them into the hands of the Philistines and into the hands of the sons of Ammon.' <em>ḥārāh ʾap</em> (H2734 H639, the anger/nose burned — idiom for divine wrath) — the burning-nose idiom for anger is physiological: flared nostrils, flushed face. The dual oppression — Philistines (west) AND Ammon (east/Transjordan) — means Israel is attacked from two directions simultaneously, the most severe judgment yet. <em>mākar</em> (H4376, to sell) — again the commercial metaphor for YHWH's judicial action: Israel's apostasy is a breach of covenant that results in covenant curses (Deut 28:36 — 'YHWH will bring you and your king to a nation that neither you nor your fathers have known').</p>",
    "10": "<p><em>wayyiṣʿaqû bənê yiśrāʾēl ʾel-YHWH lēʾmōr ḥāṭāʾnû lāk kî-ʿāzaḇnû ʾet-ʾĕlōhênû wanaʿăḇōd ʾet-habbəʿālîm</em> — 'The sons of Israel cried out to YHWH, saying: We have sinned against you, for we have forsaken our God and served the Baals.' This is the most explicit corporate confession in Judges: <em>ḥāṭāʾnû lāk</em> (we have sinned to/against you — the covenant-violation formula), <em>ʿāzaḇ</em> (H5800, to forsake/abandon — the covenant desertion term opposite of <em>dāḇaq</em> to cling/cleave to, Deut 10:20), <em>ʿāḇad</em> (H5647, to serve — the word for both slave-labor and worship; to worship Baal is to be enslaved to Baal). The confession identifies the sin precisely: not merely wrongdoing but covenant infidelity — forsaking a person (YHWH) for a rival.</p>",
    "14": "<p><em>ləkû wəziʿaqû ʾel-hāʾĕlōhîm ʾăšer bəḥartem bāhem hēmmāh yôšîʿû lākem bəʿēt ṣāratkêm</em> — 'Go and cry out to the gods whom you have chosen. Let them save you in your time of distress.' YHWH's sarcasm — 'go cry to the gods you chose' — is covenant-lawsuit rhetoric (<em>rîḇ</em> H7379 pattern). The verb <em>bāḥar</em> (H977, to choose) echoes Deuteronomy's repeated assertion that Israel chose YHWH (Deut 26:17-18) and YHWH chose Israel — here the choice is inverted: Israel chose foreign gods and must now experience the logical consequence of that choice. <em>ṣārāh</em> (H6869, distress/trouble/straits) — the gods of Ammon/Philistia cannot deliver from <em>ṣārāh</em>; only YHWH, the God of the Exodus, can.</p>",
    "16": "<p><em>wayyāsîrû ʾet-ʾĕlōhê hannēkār miqqirḇām wayyaʿabdû ʾet-YHWH wattiqqṣar napšô bəʿămal yiśrāʾēl</em> — 'They put away the foreign gods from among them and served YHWH, and he became impatient over the misery of Israel.' <em>ʾĕlōhê hannēkār</em> (H5236, foreign gods — gods of the strange/alien — these are the gods of the other nations, not just any unknown deity; the term <em>nēkār</em> implies both foreignness and strangeness). <em>wattiqqṣar napšô</em> — 'his soul/being was shortened/impatient' — <em>qāṣar</em> (H7114, to be short/cut short; with <em>nepeš</em> it means to feel distress, to be grieved, to be unable to endure — cf. Num 21:4 where Israel's soul 'became short' on the way). YHWH is not a detached judge but a personal being capable of emotional response to human suffering. This verse is one of the most striking expressions of divine pathos in the OT: Israel's <em>ʿāmal</em> (H5999, toil/misery/trouble — the word for the crushing labor of oppression) registers in YHWH's own inner life.</p>"
  }
}

def main():
    c = load_comm('mkt-original', 'judges')
    merge_comm(c, ORIGINAL)
    save_comm('mkt-original', 'judges', c)
    print(f'judges mkt-original: wrote {sum(len(v) for v in ORIGINAL.values())} verses across ch 9-10')

if __name__ == '__main__':
    main()
